// PURPOSE: Convert ISO publish_date string to Unix timestamp (seconds)
// Podbean publish_timestamp field requires Unix epoch integer, not ISO string
// Also builds a human-readable EST date string for the client confirmation email

const wh = $('Webhook — Receive Podcast Payload').first().json;
const body = wh.body || wh;
const dateStr = body.publish_date;

if (!dateStr) {
  throw new Error('Missing required field: publish_date. Expected ISO format: 2025-01-28T09:00:00. Received keys: ' + Object.keys(body).join(', '));
}

const dt = new Date(dateStr);
const publish_timestamp = Math.floor(dt.getTime() / 1000);

if (isNaN(publish_timestamp)) {
  throw new Error('Invalid publish_date value: ' + dateStr + '. Use ISO format: 2025-01-28T09:00:00');
}

const publish_date_readable = dt.toLocaleString('en-US', {
  timeZone: 'America/New_York',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  timeZoneName: 'short'
});

return [{ json: { publish_timestamp, publish_date_readable } }];

// PURPOSE: Determine the next sequential episode number from the Podbean episode list
// Scans all returned episodes for the highest episode_number value
// Falls back to total episode count if no episode_number values are set on existing episodes
// Edge case: starts at 1 for brand new channels with zero published episodes

const data = $input.first().json;
const episodes = data.episodes || [];
let maxEpisodeNumber = 0;

for (const ep of episodes) {
  const num = parseInt(ep.episode_number || '0', 10);
  if (!isNaN(num) && num > maxEpisodeNumber) {
    maxEpisodeNumber = num;
  }
}

let nextNumber;

if (maxEpisodeNumber > 0) {
  // Use highest found episode_number + 1
  nextNumber = maxEpisodeNumber + 1;
} else {
  // No episode numbers set on existing episodes — fall back to total count
  nextNumber = (parseInt(data.total || '0', 10)) + 1;
}

// Safety net: brand new channel with no episodes starts at 1
if (!nextNumber || isNaN(nextNumber) || nextNumber <= 0) {
  nextNumber = 1;
}

return [{ json: { next_episode_number: nextNumber } }];

// PURPOSE: Package audio binary for Podbean S3 upload
// Calculates actual byte filesize — Podbean requires this upfront in uploadAuthorize
// to pre-allocate the correct amount of S3 storage space
// Builds a zero-padded filename for consistent channel organization

const audioBinary = $input.first().binary?.audio;

if (!audioBinary) {
  throw new Error('No audio binary found. Verify the GHL audio_url is publicly accessible and returns a valid MP3 file.');
}

const episode_number = $('Set Config — Consolidate Workflow Variables').first().json.episode_number;
const access_token = $('Set Config — Consolidate Workflow Variables').first().json.access_token;

// Calculate byte size from base64 binary for Podbean storage pre-allocation
const buffer = Buffer.from(audioBinary.data, 'base64');
const filesize = buffer.length;

// Zero-pad episode number for consistent filename ordering across the channel
const paddedEpisode = String(episode_number).padStart(4, '0');

return [{
  json: {
    audioFilename: `episode_${paddedEpisode}.mp3`,
    audioFilesize: filesize,
    audioContentType: 'audio/mpeg',
    access_token
  },
  binary: { audio: audioBinary }
}];

// PURPOSE: Reattach audio binary to the presigned URL data
// n8n HTTP Request nodes drop binary data when they return a JSON response
// This node retrieves the audio binary from Prepare Audio Upload and reunites it
// with the presigned URL from uploadAuthorize so the PUT node has both

const authData = $input.first().json;
const audioBinary = $('Prepare Audio Upload — Package for Podbean S3').first().binary?.audio;

if (!audioBinary) {
  throw new Error('Audio binary lost in transit. Check Prepare Audio Upload node output.');
}

if (!authData.presigned_url) {
  throw new Error('No presigned_url returned from Podbean uploadAuthorize Audio. Check access token validity and file parameters.');
}

return [{
  json: {
    presigned_url: authData.presigned_url,
    file_key: authData.file_key
  },
  binary: { audio: audioBinary }
}];

// PURPOSE: Package cover image binary for Podbean S3 upload
// Detects image format (JPEG or PNG) from binary mimeType — does NOT assume JPEG
// Podbean + Apple Podcasts accept JPEG and PNG only. WebP, GIF, and other formats
// are rejected by Apple Podcasts downstream so we fail fast here with a clear message.
// Calculates byte filesize for the uploadAuthorize request.
// Captures and carries forward the audio file_key as media_key so Set Upload Keys
// can access it cleanly without a long back-reference chain.

const imageOutput = $input.first();
const imageBinary = imageOutput.binary?.image;

if (!imageBinary) {
  throw new Error('No image binary found. Verify the GHL image_url is publicly accessible and returns a valid image file.');
}

// Detect format from MIME type reported by the download
const mimeType = (imageBinary.mimeType || '').toLowerCase();

let imageContentType;
let imageExtension;

if (mimeType === 'image/jpeg' || mimeType === 'image/jpg') {
  imageContentType = 'image/jpeg';
  imageExtension = 'jpg';
} else if (mimeType === 'image/png') {
  imageContentType = 'image/png';
  imageExtension = 'png';
} else {
  // WebP, GIF, TIFF, BMP, AVIF etc. are all rejected by Apple Podcasts
  // Podbean enforces Apple's spec — these will fail at distribution
  throw new Error(
    'Unsupported image format: ' + mimeType + '. ' +
    'Podbean and Apple Podcasts accept JPEG (.jpg) and PNG (.png) only. ' +
    'WebP, GIF, and other formats will be rejected. Please re-export the cover art as JPEG or PNG and re-upload to GHL.'
  );
}

const episode_number = $('Set Config — Consolidate Workflow Variables').first().json.episode_number;
const access_token = $('Set Config — Consolidate Workflow Variables').first().json.access_token;

// Carry audio file_key forward — it becomes media_key in the publish call
const media_key = $('Podbean — uploadAuthorize Audio').first().json.file_key;

// Calculate byte size from base64 binary
const buffer = Buffer.from(imageBinary.data, 'base64');
const filesize = buffer.length;

const paddedEpisode = String(episode_number).padStart(4, '0');

return [{
  json: {
    imageFilename: `episode_${paddedEpisode}_cover.${imageExtension}`,
    imageFilesize: filesize,
    imageContentType,
    access_token,
    media_key
  },
  binary: { image: imageBinary }
}];

// PURPOSE: Reattach image binary to presigned URL data
// Same pattern as Merge Audio Binary — HTTP Request nodes drop binaries on JSON responses
// Retrieves image binary from Prepare Image Upload and reunites it with
// the presigned URL from uploadAuthorize Image for the S3 PUT upload

const authData = $input.first().json;
const imageBinary = $('Prepare Image Upload — Package for Podbean S3').first().binary?.image;

if (!imageBinary) {
  throw new Error('Image binary lost in transit. Check Prepare Image Upload node output.');
}

if (!authData.presigned_url) {
  throw new Error('No presigned_url returned from Podbean uploadAuthorize Image. Check access token and file parameters.');
}

return [{
  json: {
    presigned_url: authData.presigned_url,
    file_key: authData.file_key
  },
  binary: { image: imageBinary }
}];

// PURPOSE: Fail-closed entry guard (GK-01 / U63). Runs immediately after the webhook,
// before ANY Podbean API call (OAuth, fetch, upload, publish), so a payload missing a
// required field -- most notably image_url, the root cause of the 2026-07-12T03:04Z
// failure -- never reaches Podbean and audio is never uploaded ahead of a later crash.
// Replaces the old failure mode where the workflow crashed deep in the pipeline
// (Download Image node, after audio was already uploaded to Podbean S3).
//
// U6 EXTENSION (2026-07-16): upgrades the entry guard to payload contract v2 (spec
// Section 3). Appended to this lineage, not a rewrite. Adds on top of the original
// seven required fields: (1) contract_version must be the literal string "2" -- wrong
// or missing value is refused with its own distinct reason so v3 payloads can be
// introduced later without silently passing this guard; (2) client_last_name and
// idempotency_key are now REQUIRED (client_last_name feeds U5's roster lookup;
// idempotency_key feeds U8's server-side idempotency ledger -- both are already read
// directly off the webhook body by downstream nodes; this guard now also refuses early
// if either is absent); (3) audio_url/image_url must be https:// specifically -- plain
// http:// is no longer tolerated (was previously accepted by the ^https?:// check);
// (4) title <= 200 chars, description <= 3000 chars (spec Section 3 rows 6-7). Output
// shape for existing consumers is UNCHANGED (guard_ok, guard_error,
// guard_missing_fields, guard_bad_url_fields, client_email, title) with two new keys
// appended: guard_contract_version_mismatch, guard_length_errors.

const wh = $('Webhook — Receive Podcast Payload').first().json;
const body = wh.body || wh;

const REQUIRED = ['podcast_id', 'audio_url', 'image_url', 'title', 'description', 'publish_date', 'client_email', 'client_last_name', 'idempotency_key'];
const missing = REQUIRED.filter((key) => {
  const v = body[key];
  return v === null || v === undefined || (typeof v === 'string' && v.trim() === '');
});

const URL_FIELDS = ['audio_url', 'image_url'];
const badUrls = URL_FIELDS.filter((key) => {
  const v = body[key];
  return typeof v === 'string' && v.trim() !== '' && !/^https:\/\//i.test(v);
});

// U6: contract_version is checked separately from "missing" so a WRONG value (present
// but not "2") gets its own refusal reason distinct from an ABSENT field.
const cv = body.contract_version;
const cvPresent = !(cv === null || cv === undefined || (typeof cv === 'string' && cv.trim() === ''));
const contractVersionMismatch = cvPresent && String(cv).trim() !== '2';
if (!cvPresent && !missing.includes('contract_version')) missing.push('contract_version');

// U6: title/description length caps (spec Section 3 rows 6-7).
const lengthErrors = [];
if (typeof body.title === 'string' && body.title.length > 200) {
  lengthErrors.push('title exceeds 200 chars (' + body.title.length + ')');
}
if (typeof body.description === 'string' && body.description.length > 3000) {
  lengthErrors.push('description exceeds 3000 chars (' + body.description.length + ')');
}

const guard_ok = missing.length === 0 && badUrls.length === 0 && !contractVersionMismatch && lengthErrors.length === 0;

let guard_error = '';
if (!guard_ok) {
  const parts = [];
  if (missing.length) parts.push('missing required field(s): ' + missing.join(', '));
  if (badUrls.length) parts.push('invalid (must be https://) URL in field(s): ' + badUrls.join(', '));
  if (contractVersionMismatch) parts.push('unsupported contract_version: "' + cv + '" (only "2" is accepted)');
  if (lengthErrors.length) parts.push(lengthErrors.join('; '));
  guard_error = 'Podcast publish REFUSED at entry guard: ' + parts.join('; ') + '. No Podbean call was made; no audio or image was uploaded.';
}

return [{
  json: {
    guard_ok,
    guard_error,
    guard_missing_fields: missing,
    guard_bad_url_fields: badUrls,
    guard_contract_version_mismatch: contractVersionMismatch,
    guard_length_errors: lengthErrors,
    client_email: body.client_email || '',
    title: body.title || '(untitled)'
  }
}];

// U5 — GOOD-STANDING + IDENTITY GATE (authoritative). Normalizes the roster lookup key pair
// (client_last_name, client_email) from the webhook payload BEFORE querying
// podcast_publish_roster, so the Data table node's exact-match filter finds the row
// regardless of payload casing/whitespace. Runs immediately after the GK-01/U63 entry guard
// passes and BEFORE any Podbean OAuth/download call (spec Section 5 U5). Email compare is
// lowercase (roster stores email lowercase); last_name compare is case-insensitive
// (roster stores last_name trimmed, original case) — handled downstream in the verdict node.

const wh = $('Webhook — Receive Podcast Payload').first().json;
const body = wh.body || wh;

const raw_last_name = (body.client_last_name || '').toString();
const raw_email = (body.client_email || '').toString();
const raw_podcast_id = (body.podcast_id || '').toString();

return [{
  json: {
    lookup_email: raw_email.trim().toLowerCase(),
    lookup_last_name_lc: raw_last_name.trim().toLowerCase(),
    raw_podcast_id: raw_podcast_id.trim()
  }
}];

// U5 — GOOD-STANDING + IDENTITY GATE — verdict. Classifies exactly one of:
// pass | identity_unknown | identity_mismatch | not_in_good_standing.
// Fail-closed: the roster lookup node has onError=continueRegularOutput, so ANY table-read
// error surfaces here as zero matched rows, which classifies as identity_unknown (refuse) —
// never pass. On pass, effective_channel_id is set from the ROSTER row; every downstream
// Podbean call (OAuth podcast_id, Set Config podcast_id -> Publish Episode podcast_id) is
// patched to read effective_channel_id, NEVER the raw payload podcast_id (spec Section 5 U5,
// Section 6 never-co-mingle).

const keys = $('Standing Gate — Normalize Lookup Keys').first().json;
const rows = $input.all().map(item => item.json);

const matched = rows.filter(r => (r.last_name || '').toString().trim().toLowerCase() === keys.lookup_last_name_lc);

let verdict, reason_detail, roster_channel_id = '', effective_channel_id = '';

if (matched.length === 0) {
  verdict = 'identity_unknown';
  reason_detail = 'no roster row for the given (last_name,email) pair';
} else {
  const row = matched[0];
  roster_channel_id = (row.podbean_channel_id || '').toString().trim();
  if (!roster_channel_id || roster_channel_id !== keys.raw_podcast_id) {
    verdict = 'identity_mismatch';
    reason_detail = 'roster row channel id does not match the payload podcast_id';
  } else if ((row.good_standing || '').toString() !== 'YES') {
    verdict = 'not_in_good_standing';
    reason_detail = 'you are not in good standing';
  } else {
    verdict = 'pass';
    reason_detail = '';
    effective_channel_id = roster_channel_id;
  }
}

return [{
  json: {
    standing_gate_verdict: verdict,
    standing_gate_passed: verdict === 'pass',
    standing_gate_reason_detail: reason_detail,
    roster_channel_id,
    payload_channel_id: keys.raw_podcast_id,
    effective_channel_id
  }
}];

// U8 — SERVER-SIDE IDEMPOTENCY (spec Section 5 U8 / Section 8). Runs AFTER the U6 entry
// guard, BEFORE the U5 standing/identity gate -- earliest possible point once the payload
// is known well-formed, so a duplicate idempotency_key never reaches the roster lookup or
// any Podbean call. Classifies exactly one of: replay | in_flight | proceed.
// Fail-open on a genuine table-read error (the lookup node has onError=continueRegularOutput
// + alwaysOutputData=true, so an error surfaces here as zero matched rows, same as
// "never seen this key before") -- the box's own client-side ledger-permalink skip
// (podbean_publish.sh lines 363-377) is the SECOND, independent guard against a true
// double-publish (spec Section 8); refusing a legitimate new publish because the ledger
// table briefly errored would be worse than the rare risk this covers.

const wh = $('Webhook — Receive Podcast Payload').first().json;
const body = wh.body || wh;
const idempotency_key = (body.idempotency_key || '').toString().trim();

const rows = $input.all().map(item => item.json).filter(r => r && r.idempotency_key);

let verdict = 'proceed';
let stored_permalink_url = '';
let stored_episode_number = '';

if (rows.length > 0) {
  const row = rows[0];
  const status = (row.status || '').toString();
  if (status === 'completed') {
    verdict = 'replay';
    stored_permalink_url = row.permalink_url || '';
    stored_episode_number = row.episode_number || '';
  } else if (status === 'received' || status === 'in_flight') {
    verdict = 'in_flight';
  } else {
    // 'failed' / 'refused' / unknown status: safe to retry with the same key
    // (spec Section 8: "Podbean 5xx: workflow fails -> ledger failed -> box retries same key (safe)").
    verdict = 'proceed';
  }
}

return [{
  json: {
    idempotency_key,
    idempotency_verdict: verdict,
    idempotency_is_replay: verdict === 'replay',
    idempotency_is_in_flight: verdict === 'in_flight',
    stored_permalink_url,
    stored_episode_number,
    raw_channel_id: (body.podcast_id || '').toString().trim(),
    raw_source: (body.source || 'unknown').toString()
  }
}];

// U11 — MEDIA PREFLIGHT (spec Section 5 U11). Runs AFTER the U5 good-standing/identity
// gate, BEFORE Compute Timestamp / Podbean OAuth (the first Podbean API call in this
// workflow) -- extends the GK-01 principle (refuse before ANY Podbean byte moves) to
// dead or empty media URLs, keeping partial-upload waste at zero.
// Criteria (spec Section 5 U11): 2xx status + content-length header present and > 0 for
// BOTH audio_url and image_url; audio_url additionally requires content-type audio/* OR
// application/octet-stream (both tolerated -- many CDNs serve audio as octet-stream). No
// content-type check on image_url (not specified by the spec text).

const wh = $('Webhook — Receive Podcast Payload').first().json;
const body = wh.body || wh;

const audioItem = $('Media Preflight — HEAD Check Audio URL').first();
const imageItem = $('Media Preflight — HEAD Check Image URL').first();

function getHeader(headers, name) {
  if (!headers) return undefined;
  const key = Object.keys(headers).find((k) => k.toLowerCase() === name.toLowerCase());
  return key ? headers[key] : undefined;
}

function checkResponse(item, url, label, requireAudioContentType) {
  const j = item ? item.json : null;
  if (!j || typeof j.statusCode !== 'number') {
    let errMsg = 'request failed or timed out';
    if (j && j.error) {
      errMsg = typeof j.error === 'string' ? j.error : (j.error.message || j.error.description || JSON.stringify(j.error));
    }
    return { ok: false, url, detail: label + ' (' + url + ') unreachable: ' + errMsg };
  }
  const status = j.statusCode;
  if (status < 200 || status >= 300) {
    return { ok: false, url, detail: label + ' (' + url + ') returned HTTP ' + status };
  }
  const headers = j.headers || {};
  const clRaw = getHeader(headers, 'content-length');
  const cl = parseInt(clRaw || '', 10);
  if (!clRaw || isNaN(cl) || cl <= 0) {
    return { ok: false, url, detail: label + ' (' + url + ') has missing or zero content-length' };
  }
  if (requireAudioContentType) {
    const ct = (getHeader(headers, 'content-type') || '').toLowerCase();
    const toleratedAudio = ct.startsWith('audio/') || ct.startsWith('application/octet-stream');
    if (!toleratedAudio) {
      return { ok: false, url, detail: label + ' (' + url + ') has non-audio content-type: ' + (ct || '(none)') };
    }
  }
  return { ok: true, url, detail: '' };
}

const audioUrl = body.audio_url || '';
const imageUrl = body.image_url || '';

const audioResult = checkResponse(audioItem, audioUrl, 'audio_url', true);
const imageResult = checkResponse(imageItem, imageUrl, 'image_url', false);

const failing = [audioResult, imageResult].filter((r) => !r.ok);
const media_preflight_passed = failing.length === 0;
const media_preflight_failing_urls = failing.map((r) => r.url);
const media_preflight_reason = failing.length
  ? failing.map((r) => r.detail).join('; ')
  : '';

return [{
  json: {
    media_preflight_passed,
    media_preflight_failing_urls,
    media_preflight_reason
  }
}];
